// Calculate yesterday's date range (UTC boundaries for CT day)
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const dateStr = yesterday.toISOString().split('T')[0];
const startOfDay = dateStr + 'T00:00:00Z';
const endOfDay = dateStr + 'T23:59:59.999Z';

return [{ json: { yesterday: dateStr, startOfDay, endOfDay } }];

// Extract payment data from the fetched jobber_email_events
const payments = $('Fetch Payment Events').first().json.body;
const yesterday = $('Calculate Yesterday').first().json.yesterday;

if (!payments || payments.length === 0) {
  return [{ json: { payments: [], count: 0 } }];
}

// Build lookup lists for lead matching
const emails = [];
const phones = [];

for (const p of payments) {
  if (p.parsed_customer_email) emails.push(p.parsed_customer_email.toLowerCase());
  if (p.parsed_customer_phone) {
    // Normalize phone: strip non-digits
    const normalized = p.parsed_customer_phone.replace(/\D/g, '');
    if (normalized.length >= 10) phones.push(normalized);
  }
}

// Deduplicate
const uniqueEmails = [...new Set(emails)];
const uniquePhones = [...new Set(phones)];

return [{ json: {
  payments,
  yesterday,
  uniqueEmails,
  uniquePhones,
  count: payments.length
} }];

// Build attribution records by matching payments to leads
const data = $('Extract Payment Data').first().json;
const leadsResponse = $('Match Leads').first().json.body;
const payments = data.payments;
const yesterday = data.yesterday;

// Build lookup maps from leads
const leadsByEmail = {};
const leadsByPhone = {};

if (Array.isArray(leadsResponse)) {
  for (const lead of leadsResponse) {
    if (lead.email) leadsByEmail[lead.email.toLowerCase()] = lead;
    if (lead.phone) {
      const normalized = lead.phone.replace(/\D/g, '');
      if (normalized.length >= 10) leadsByPhone[normalized] = lead;
    }
  }
}

// Build attribution records
const attributions = [];

for (const payment of payments) {
  let matchedLead = null;

  // Try email match first
  if (payment.parsed_customer_email) {
    const email = payment.parsed_customer_email.toLowerCase();
    if (leadsByEmail[email]) matchedLead = leadsByEmail[email];
  }

  // Try phone match if no email match
  if (!matchedLead && payment.parsed_customer_phone) {
    const phone = payment.parsed_customer_phone.replace(/\D/g, '');
    if (phone.length >= 10 && leadsByPhone[phone]) matchedLead = leadsByPhone[phone];
  }

  const attribution = {
    lead_id: matchedLead ? matchedLead.id : null,
    revenue: payment.parsed_amount || 0,
    lead_source: matchedLead ? (matchedLead.source || 'unknown') : 'unknown',
    service_type: payment.parsed_service || null,
    attributed_at: payment.parsed_at || payment.created_at || new Date().toISOString()
  };

  attributions.push(attribution);
}

return [{ json: {
  attributions,
  matchedCount: attributions.filter(a => a.lead_id !== null).length,
  unmatchedCount: attributions.filter(a => a.lead_id === null).length,
  totalRevenue: attributions.reduce((sum, a) => sum + (a.revenue || 0), 0)
} }];

// Log summary of the sync
const data = $('Build Attribution Records').first().json;
return [{ json: {
  status: 'complete',
  totalPayments: data.attributions.length,
  matchedToLeads: data.matchedCount,
  unmatchedPayments: data.unmatchedCount,
  totalRevenue: data.totalRevenue,
  syncedAt: new Date().toISOString()
} }];

// No payments found yesterday — log and exit cleanly
const yesterday = $('Calculate Yesterday').first().json.yesterday;
return [{ json: {
  status: 'no_payments',
  message: `No payment_received events found for ${yesterday}`,
  syncedAt: new Date().toISOString()
} }];
